Code.Terraform:
```hcl
# 最简 VPC 配置：1 个公有子网、2 个私有子网以及一个 NAT 网关
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.0.0/24"
}

resource "aws_subnet" "private_a" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"  # 私有子网 1（必填/必需）
}

resource "aws_subnet" "private_b" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"  # 私有子网 2（必填/必需）
}

resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id               # 关键要点：为私有子网的出站流量配置 NAT 
  subnet_id     = aws_subnet.public.id         # 关键要点：NAT 必须位于公有子网中
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {                                      # 关键要点：此操作会将该子网变为“公有”子网
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {                                      # 关键要点：私有子网必须使用 NAT 访问互联网
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }
}

resource "aws_route_table_association" "private_a" {
  subnet_id      = aws_subnet.private_a.id     # 至关重要：工作区子网必须关联到私有路由表。
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_b" {
  subnet_id      = aws_subnet.private_b.id
  route_table_id = aws_route_table.private.id  # 至关重要：确保至少有两个私有子网。 
}
```
